4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block stable (still life)", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.length).toBe(4);
18	    expect(new Set(result.map(c => c.join(",")))).toEqual(
19	      new Set(block.map(c => c.join(",")))
20	    );
21	  });
